};

var maxWeight = function(weights) {
    weights.sort((a, b) => b - a);

    let n = weights.length;
    let bag1 = 0, bag2 = 0;

    for (let i = 0; i < n / 2; i++)
        bag1 += weights[i];

    for (let i = Math.floor(n / 2); i < n; i++)
        bag2 += weights[i];

    return Math.abs(bag1 - bag2);
};

