};

var trionic = function(nums) {
    let n = nums.length;
    let inc = new Array(n).fill(1);
    let dec = new Array(n).fill(1);

    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1])
            inc[i] = inc[i - 1] + 1;
    }

    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] > nums[i + 1])
            dec[i] = dec[i + 1] + 1;
    }

    let ans = 0;

    for (let i = 0; i < n; i++)
        ans = Math.max(ans, inc[i] + dec[i] - 1);

    return ans;
};

