class MajorityChecker {
    constructor(arr) {
        this.pos = new Map();

        for (let i = 0; i < arr.length; i++) {
            if (!this.pos.has(arr[i]))
                this.pos.set(arr[i], []);

            this.pos.get(arr[i]).push(i);
        }
    }

    query(left, right, threshold) {
        for (let [num, indices] of this.pos.entries()) {
            let cnt = this.upperBound(indices, right) - this.lowerBound(indices, left);

            if (cnt >= threshold)
                return num;
        }

        return -1;
    }

    lowerBound(arr, target) {
        let l = 0, r = arr.length;

        while (l < r) {
            let m = Math.floor((l + r) / 2);

            if (arr[m] < target)
                l = m + 1;
            else
                r = m;
        }

        return l;
    }

    upperBound(arr, target) {
        let l = 0, r = arr.length;

        while (l < r) {
            let m = Math.floor((l + r) / 2);

            if (arr[m] <= target)
                l = m + 1;
            else
                r = m;
        }

        return l;
    }
}

