var minCost = function(grid) {
    const n = grid.length;
    const m = grid[0].length;

    let dist = Array.from({length:n},()=>Array(m).fill(Infinity));
    let q = [[0,0]];
    dist[0][0] = 0;

    let dx = [0,0,1,-1];
    let dy = [1,-1,0,0];

    while(q.length){
        let [x,y] = q.shift();

        for(let d=0; d<4; d++){
            let nx=x+dx[d], ny=y+dy[d];

            if(nx>=0 && ny>=0 && nx<n && ny<m){
                let cost = dist[x][y] + (grid[x][y] !== d+1);

                if(cost < dist[nx][ny]){
                    dist[nx][ny]=cost;
                    q.push([nx,ny]);
                }
            }
        }
    }

    return dist[n-1][m-1];
};

var minMoves = function(grid) {
    let n = grid.length;
    let q = [[0,0,0]];
    let vis = new Set(['0,0']);

    let dx=[1,-1,0,0];
    let dy=[0,0,1,-1];

    while(q.length){
        let [x,y,d]=q.shift();

        if(x===n-1 && y===n-1)
            return d;

        for(let i=0;i<4;i++){
            let nx=x+dx[i], ny=y+dy[i];

            if(nx>=0 && ny>=0 && nx<n && ny<n && grid[nx][ny]===0){
                let key=`${nx},${ny}`;

                if(!vis.has(key)){
                    vis.add(key);
                    q.push([nx,ny,d+1]);
                }
            }
        }
    }

    return -1;
};

