    const find = (x) => {
        if (parent[x] !== x)
            parent[x] = find(parent[x]);
        return parent[x];
    };

    const union = (a, b) => {
        parent[find(a)] = find(b);
    };

    edges.sort((a, b) => a[2] - b[2]);

    let ans = 0;

    for (let [u, v, w] of edges) {
        if (find(u) !== find(v)) {
            union(u, v);
            ans += w;
        }
    }

    return ans;
};

