        if (visited[i] || arr[i][1] === i)
            continue;

        let cycle = 0;
        let j = i;

        while (!visited[j]) {
            visited[j] = true;
            j = arr[j][1];
            cycle++;
        }

        swaps += cycle - 1;
    }

    return swaps;
};

var canPartitionGrid = function(grid) {
    let total = 0;

    for (let row of grid) {
        for (let val of row)
            total += val;
    }

    let prefix = 0;

    for (let row of grid) {
        for (let val of row)
            prefix += val;

        if (prefix * 2 === total)
            return true;
    }

    return false;
};

